export const worldMapRegionIds = worldMapRegions.map((region) => region.id);

export function projectLatLng(lng: number, lat: number) {
  return {
    x: ((lng + 180) / 360) * worldMapViewBox.width,
    y: ((90 - lat) / 180) * worldMapViewBox.height,
  };
}

export function normalizeRegionId(label: string) {
  return label.trim().toLowerCase().replace(/\s+/g, "-");
}

export function fitWorldMapToPlot(plot: {
  bottom: number;
  gridLeft: number;
  gridRight: number;
  top: number;
}) {
  const pad = 2;
  const availW = plot.gridRight - plot.gridLeft - pad * 2;
  const availH = plot.bottom - plot.top - pad * 2;
  const scale = Math.min(availW / worldMapViewBox.width, availH / worldMapViewBox.height);
  const x = plot.gridLeft + pad + (availW - worldMapViewBox.width * scale) / 2;
  const y = plot.top + pad + (availH - worldMapViewBox.height * scale) / 2;
  return { scale, x, y };
}

export function getRegionCentroid(regionId: string) {
  const key = normalizeRegionId(regionId);
  return worldMapCentroids[key] ?? null;
}

export function getRegionById(regionId: string) {
  const key = normalizeRegionId(regionId);
  return worldMapRegions.find((region) => region.id === key || normalizeRegionId(region.label) === key);
}

export function resolveRegionId(item: { label: string; region?: string }) {
  return item.region ?? normalizeRegionId(item.label);
}
